
package com.example.taxgap.service; import com.example.taxgap.domain.entity.AuditLog; import com.example.taxgap.domain.enums.EventType; import com.example.taxgap.repository.AuditLogRepository; import com.fasterxml.jackson.databind.ObjectMapper; import org.springframework.stereotype.Service;
@Service public class AuditLogService { private final AuditLogRepository repo; private final ObjectMapper mapper; public AuditLogService(AuditLogRepository repo, ObjectMapper mapper){this.repo=repo;this.mapper=mapper;} public void log(EventType type, String txnId, Object details){ try{ AuditLog log=new AuditLog(); log.setEventType(type); log.setTransactionId(txnId); log.setDetailJson(details==null?null:mapper.writeValueAsString(details)); repo.save(log);}catch(Exception e){ System.err.println("Audit logging failed: "+e.getMessage()); } } }
